LAYER
  NAME "SWC"
   TYPE RASTER
   STATUS ON
   PROJECTION
      "init=epsg:31370"
   END
   DATA "soilWaterCapacity.tif" 
   PROCESSING "BANDS=1" 
   CLASSITEM "[pixel]" 
      CLASS 
      NAME "Contrainte Extrème (de 0 à 40 mm)"
      EXPRESSION ([pixel]>-1 AND [pixel]<=40)
      STYLE 
          COLOR 132 17 119
       END
   END
   CLASS 
      NAME "Contrainte Majeure (de 40 à 70 mm)"
      EXPRESSION ([pixel]>40 AND [pixel]<=70)
      STYLE 
          COLOR 183 59 31
       END
   END
   CLASS 
      NAME "Contrainte Forte (de 70 à 100 mm)"
      EXPRESSION ([pixel]>70 AND [pixel]<=100)
      STYLE 
          COLOR 193 116 28
       END
   END
   CLASS 
      NAME "Contrainte Moyenne (de 100 mm à 150 mm)"
      EXPRESSION ([pixel]>100 AND [pixel]<=150)
      STYLE 
          COLOR 255 220 63
       END
   END
   CLASS 
      NAME "Contrainte Faible (de 150 mm à 200 mm)"
       EXPRESSION ([pixel]>150 AND [pixel]<=200)
      STYLE 
          COLOR 45 103 22
       END
   END
   CLASS 
      NAME "Aucune Contrainte ( plus de 200 mm)"
       EXPRESSION ([pixel]>200)
      STYLE 
      	COLOR 19 38 160
       END
   END

 METADATA
      "wms_title"           "Réserve en eau du sol"
      "wms_srs"             "EPSG:31370"
   END
   TEMPLATE "../template.html"
END

